SELECT events.repo_name, events.event_count AS combined_total FROM (SELECT "repo":"name" AS repo_name, COUNT(*) AS event_count FROM "GITHUB_REPOS_DATE"."MONTH"."_202204" WHERE "type" IN ('ForkEvent', 'IssuesEvent', 'WatchEvent') GROUP BY "repo":"name") events INNER JOIN (SELECT DISTINCT "repo_name" FROM "GITHUB_REPOS_DATE"."GITHUB_REPOS"."LICENSES") licenses ON events.repo_name = licenses."repo_name" ORDER BY events.event_count DESC LIMIT 1